16	export async function getMetricsSummary(): Promise<MetricsSummaryResponse> {
17	  const metrics = await repo.getLatestMetrics();
18	  const byName: Record<string, number> = {};
19	  let latestCollectedAt: Date | null = null;
20	
21	  for (const m of metrics) {
22	    byName[m.metricName] = m.value;
23	    if (!latestCollectedAt || m.collectedAt > latestCollectedAt) {
24	      latestCollectedAt = m.collectedAt;
25	    }
26	  }
27	
28	  return {
29	    p95Latency: byName[MetricName.P95_LATENCY] ?? null,
30	    cpuUtilization: byName[MetricName.CPU_UTILIZATION] ?? null,
31	    gpuUtilization: byName[MetricName.GPU_UTILIZATION] ?? null,
32	    errorRate: byName[MetricName.ERROR_RATE] ?? null,
33	    collectedAt: latestCollectedAt?.toISOString() ?? null,
34	  };
35	}
