37	// ---- Threshold evaluation (called on each metric ingestion) ----
38	
39	async function checkThresholds(metricName: string, value: number): Promise<void> {
40	  const thresholds = await repo.findActiveThresholdsForMetric(metricName);
41	  for (const threshold of thresholds) {
42	    const triggered = evaluateThreshold(value, threshold.operator as any, threshold.thresholdValue);
43	    if (!triggered) continue;
44	
45	    const orgId = threshold.orgId ?? undefined;
46	    const event = await repo.createAlertEvent(threshold.id, value, orgId);
47	    await repo.createNotification({
48	      alertEventId: event.id,
49	      type: NotificationType.BANNER,
50	      message: `Alert: ${metricName} ${threshold.operator} ${threshold.thresholdValue} (actual: ${value})`,
51	      orgId,
52	    });
53	
54	    // Critical alerts also emit an audible notification for workstation awareness.
55	    if (metricName === MetricName.ERROR_RATE) {
56	      await repo.createNotification({
57	        alertEventId: event.id,
58	        type: NotificationType.AUDIBLE,
59	        message: `Audible alert: ${metricName} ${threshold.operator} ${threshold.thresholdValue} (actual: ${value})`,
60	        orgId,
61	      });
62	    }
63	  }
64	}
