28	export async function searchLogs(filters: LogSearchRequest, page = 1, limit = 50, orgId?: string) {
29	  const skip = (page - 1) * limit;
30	  const where: Record<string, unknown> = {};
31	
32	  if (filters.level) where.level = filters.level;
33	  if (filters.search) where.message = { contains: filters.search };
34	  if (orgId) where.orgId = orgId;
35	
36	  if (filters.startDate || filters.endDate) {
37	    const tsFilter: Record<string, Date> = {};
38	    if (filters.startDate) tsFilter.gte = new Date(filters.startDate);
39	    if (filters.endDate) tsFilter.lte = new Date(filters.endDate);
40	    where.timestamp = tsFilter;
41	  }
42	
43	  const [logs, total] = await Promise.all([
44	    db.applicationLog.findMany({
45	      where,
46	      orderBy: { timestamp: 'desc' },
47	      skip,
48	      take: limit,
49	    }),
50	    db.applicationLog.count({ where }),
51	  ]);
52	
53	  return { logs, total };
54	}
