1	import { Request, Response, NextFunction } from 'express';
2	import { verifySignature } from '../signing/api-signer.js';
3	import { UnauthorizedError } from '../errors/app-errors.js';
4	import { config } from '../../app/config.js';
5	
6	/**
7	 * Verifies HMAC-SHA256 signatures for internal signed integration endpoints.
8	 * Agents must include:
9	 *   X-Signature: <hex-signature>
10	 *   X-Timestamp: <unix-ms>
11	 */
12	export function verifySigning(req: Request, res: Response, next: NextFunction): void {
13	  const signature = req.headers['x-signature'] as string | undefined;
14	  const timestampHeader = req.headers['x-timestamp'] as string | undefined;
15	
16	  if (!signature || !timestampHeader) {
17	    next(new UnauthorizedError('Missing signing headers (X-Signature, X-Timestamp)'));
18	    return;
19	  }
20	
21	  const timestampMs = Number(timestampHeader);
22	  if (isNaN(timestampMs)) {
23	    next(new UnauthorizedError('Invalid X-Timestamp header'));
24	    return;
25	  }
26	
27	  const payload = JSON.stringify(req.body ?? {});
28	  const valid = verifySignature(payload, config.INTEGRATION_SIGNING_SECRET, signature, timestampMs);
29	
30	  if (!valid) {
31	    next(new UnauthorizedError('Invalid or expired request signature'));
32	    return;
33	  }
34	
35	  next();
36	}
