1	import * as fs from 'fs';
2	import * as path from 'path';
3	import axios from 'axios';
4	import { BaseWorker } from './base-worker.js';
5	import { db } from '../../app/container.js';
6	import { decrypt } from '../../common/encryption/aes256.js';
7	import { logger } from '../../common/logging/logger.js';
8	import { getOrCreateBreaker } from '../../common/circuit-breaker/circuit-breaker.js';
9	import { addTrackingUpdate, upsertSyncCursor } from '../../modules/logistics/repository.js';
10	
11	const carrierApiBreaker = getOrCreateBreaker('carrier-sync-rest-api', {
12	  failureThreshold: 5,
13	  successThreshold: 2,
14	  openTimeoutMs: 5 * 60 * 1000,
15	});
16	
17	export class CarrierSyncWorker extends BaseWorker {
18	  readonly type = 'carrier_sync';
19	
20	  async handle(payload: object): Promise<void> {
21	    const { carrierId } = payload as { carrierId: string };
22	
23	    const carrier = await db.carrier.findUnique({ where: { id: carrierId } });
24	    if (!carrier) {
25	      logger.warn({ carrierId }, 'Carrier not found for sync');
26	      return;
27	    }
28	
29	    const connectorConfig = carrier.connectorConfig ? decrypt(carrier.connectorConfig) : null;
30	    const cursor = await db.carrierSyncCursor.findUnique({ where: { carrierId } });
31	
32	    try {
33	      if (carrier.connectorType === 'manual') {
34	        // No-op for manual carriers — just update cursor timestamp
35	        logger.info({ carrierId, connectorType: 'manual' }, 'Manual carrier sync: no-op');
36	
37	      } else if (carrier.connectorType === 'rest_api') {
38	        const cfg = JSON.parse(connectorConfig ?? '{}') as {
39	          apiUrl: string;
40	          apiKey?: string;
41	          timeoutMs?: number;
42	        };
43	
44	        const since = cursor?.lastSyncAt?.toISOString() ?? '';
45	        const response = await carrierApiBreaker.execute(() =>
46	          axios.get<unknown[]>(cfg.apiUrl, {
47	            params: { since },
48	            headers: cfg.apiKey ? { Authorization: `Bearer ${cfg.apiKey}` } : {},
49	            timeout: cfg.timeoutMs ?? 10000,
50	          }),
51	        );
52	
53	        const updates = Array.isArray(response.data) ? response.data : [];
54	        for (const update of updates) {
55	          const u = update as { shipmentId?: string; status?: string; location?: string };
56	          if (u.shipmentId && u.status) {
57	            await addTrackingUpdate(u.shipmentId, u.status, u.location ?? null, 'carrier_sync');
58	          }
59	        }
60	
61	        await upsertSyncCursor(carrierId, {
62	          lastSyncAt: new Date(),
63	          lastSuccessCursor: new Date().toISOString(),
64	          errorState: null,
65	        });
66	
67	        logger.info({ carrierId, updatesProcessed: updates.length }, 'Carrier sync: rest_api completed');
68	
69	      } else if (carrier.connectorType === 'file_drop') {
70	        const cfg = JSON.parse(connectorConfig ?? '{}') as {
71	          watchDirectory: string;
72	          processedDirectory?: string;
73	        };
74	
75	        const watchDir = cfg.watchDirectory;
76	        const processedDir = cfg.processedDirectory ?? path.join(watchDir, 'processed');
77	
78	        if (!fs.existsSync(watchDir)) {
79	          logger.warn({ carrierId, watchDir }, 'Carrier sync: watch directory not found');
80	          await upsertSyncCursor(carrierId, { lastSyncAt: new Date(), errorState: null });
81	          return;
82	        }
83	
84	        fs.mkdirSync(processedDir, { recursive: true });
85	
86	        const files = fs.readdirSync(watchDir).filter((f) => f.endsWith('.json'));
87	        let updatesProcessed = 0;
88	
89	        for (const file of files) {
90	          const filePath = path.join(watchDir, file);
91	          const stat = fs.statSync(filePath);
92	
93	          // Skip files not modified after last sync
94	          if (cursor?.lastSyncAt && stat.mtime <= cursor.lastSyncAt) continue;
95	
96	          try {
97	            const content = fs.readFileSync(filePath, 'utf-8');
98	            const updates = JSON.parse(content) as unknown[];
99	            const updateList = Array.isArray(updates) ? updates : [updates];
100	
101	            for (const update of updateList) {
102	              const u = update as { shipmentId?: string; status?: string; location?: string };
103	              if (u.shipmentId && u.status) {
104	                await addTrackingUpdate(u.shipmentId, u.status, u.location ?? null, 'carrier_sync');
105	                updatesProcessed++;
106	              }
107	            }
108	
109	            // Move processed file
110	            fs.renameSync(filePath, path.join(processedDir, file));
111	          } catch (fileErr) {
112	            logger.warn({ carrierId, file, err: String(fileErr) }, 'Carrier sync: failed to process file');
113	          }
114	        }
115	
116	        await upsertSyncCursor(carrierId, {
117	          lastSyncAt: new Date(),
118	          lastSuccessCursor: new Date().toISOString(),
119	          errorState: null,
120	        });
121	
122	        logger.info({ carrierId, updatesProcessed }, 'Carrier sync: file_drop completed');
123	      }
124	
125	      // Upsert sync cursor with updated timestamp for all types
126	      await db.carrierSyncCursor.upsert({
127	        where: { carrierId },
128	        update: { lastSyncAt: new Date(), errorState: null },
129	        create: {
130	          carrierId,
131	          lastSyncAt: new Date(),
132	          lastSuccessCursor: cursor?.lastSuccessCursor ?? null,
133	          errorState: null,
134	        },
135	      });
136	
137	      logger.info({ carrierId }, 'Carrier sync cursor updated');
138	    } catch (err) {
139	      const errorState = String(err);
