4	class DatabaseTransport extends TransportStream {
5	  log(info: Record<string, unknown>, callback: () => void): void {
6	    setImmediate(callback); // never block the logger
7	    // Lazy import to avoid circular dependency at module load time
8	    import('../../app/container.js').then(({ db }) => {
9	      const { level, message, ...rest } = info;
10	      const orgId = typeof rest['orgId'] === 'string' ? rest['orgId'] : null;
11	      const context = { ...rest };
12	      delete context['orgId'];
13	      db.applicationLog.create({
14	        data: {
15	          level: String(level),
16	          message: typeof message === 'string' ? message : JSON.stringify(message),
17	          context: JSON.stringify(context),
18	          orgId,
19	        },
20	      }).catch(() => {}); // swallow DB errors — never crash the logger
21	    }).catch(() => {});
22	  }
23	}
24	
25	const REDACTED_KEYS = new Set([
26	  'password',
27	  'passwordhash',
28	  'salt',
29	  'token',
30	  'secret',
31	  'key',
32	  'authorization',
33	  'encryptedbalance',
34	  'connectorconfig',
35	  'aeskey',
36	  'jwtsecret',
37	]);
38	
39	const BEARER_PATTERN = /Bearer\s+[A-Za-z0-9\-._~+/]+=*/g;
40	
41	function sanitizeValue(value: unknown): unknown {
42	  if (typeof value === 'string') {
43	    return value.replace(BEARER_PATTERN, 'Bearer [REDACTED]');
44	  }
45	  if (Array.isArray(value)) {
46	    return value.map(sanitizeValue);
47	  }
48	  if (value !== null && typeof value === 'object') {
49	    return sanitizeObject(value as Record<string, unknown>);
50	  }
51	  return value;
52	}
53	
54	function sanitizeObject(obj: Record<string, unknown>): Record<string, unknown> {
55	  const result: Record<string, unknown> = {};
56	  for (const [k, v] of Object.entries(obj)) {
57	    if (REDACTED_KEYS.has(k.toLowerCase())) {
58	      result[k] = '[REDACTED]';
59	    } else {
60	      result[k] = sanitizeValue(v);
61	    }
62	  }
63	  return result;
64	}
65	
66	const sanitizeTransform = winston.format((info) => {
67	  const sanitized = sanitizeObject(info as unknown as Record<string, unknown>);
68	  return Object.assign(info, sanitized);
69	});
70	
71	const isDev = process.env['NODE_ENV'] === 'development';
72	
73	export const logger = winston.createLogger({
74	  level: isDev ? 'debug' : 'info',
75	  format: isDev
76	    ? winston.format.combine(
77	        sanitizeTransform(),
78	        winston.format.colorize(),
79	        winston.format.simple(),
80	      )
81	    : winston.format.combine(sanitizeTransform(), winston.format.json()),
82	  transports: [
83	    new winston.transports.Console(),
84	    new DatabaseTransport({ level: 'info' }),
85	  ],
86	});
