1	import { createCipheriv, createDecipheriv, randomBytes, createHash } from 'crypto';
2	import { config } from '../../app/config.js';
3	import { InternalError } from '../errors/app-errors.js';
4	
5	let KEY: Buffer;
6	
7	function getKey(): Buffer {
8	  if (!KEY) {
9	    KEY = Buffer.from(config.AES_KEY, 'hex');
10	    if (KEY.length !== 32) {
11	      throw new InternalError('AES_KEY must decode to exactly 32 bytes');
12	    }
13	  }
14	  return KEY;
15	}
16	
17	export function encrypt(plaintext: string): string {
18	  const key = getKey();
19	  const iv = randomBytes(12);
20	  const cipher = createCipheriv('aes-256-gcm', key, iv);
21	  const encrypted = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
22	  const authTag = cipher.getAuthTag();
23	
24	  return [iv.toString('base64'), authTag.toString('base64'), encrypted.toString('base64')].join(
25	    ':',
26	  );
27	}
28	
29	export function decrypt(encryptedData: string): string {
30	  const key = getKey();
31	  const parts = encryptedData.split(':');
32	  if (parts.length !== 3) {
33	    throw new InternalError('Invalid encrypted data format');
34	  }
35	
36	  const [ivB64, tagB64, cipherB64] = parts;
37	  const iv = Buffer.from(ivB64!, 'base64');
38	  const authTag = Buffer.from(tagB64!, 'base64');
39	  const ciphertext = Buffer.from(cipherB64!, 'base64');
40	
41	  try {
42	    const decipher = createDecipheriv('aes-256-gcm', key, iv);
43	    decipher.setAuthTag(authTag);
44	    const decrypted = Buffer.concat([decipher.update(ciphertext), decipher.final()]);
45	    return decrypted.toString('utf8');
46	  } catch {
47	    throw new InternalError('Decryption failed — authentication tag verification error');
48	  }
49	}
50	
51	export function hashField(value: string): string {
52	  return createHash('sha256').update(value).digest('hex');
53	}
