16	async function computeDHash(buffer: Buffer): Promise<string> {
17	  const { data } = await sharp(buffer)
18	    .grayscale()
19	    .resize(9, 8, { fit: 'fill' })
20	    .raw()
21	    .toBuffer({ resolveWithObject: true });
22	
23	  let bits = '';
24	  for (let row = 0; row < 8; row++) {
25	    for (let col = 0; col < 8; col++) {
26	      const left = data[row * 9 + col] ?? 0;
27	      const right = data[row * 9 + col + 1] ?? 0;
28	      bits += left > right ? '1' : '0';
29	    }
30	  }
31	
32	  let hash = '';
33	  for (let i = 0; i < 64; i += 4) {
34	    hash += Number.parseInt(bits.slice(i, i + 4), 2).toString(16);
35	  }
36	  return hash.padStart(16, '0');
37	}
