2	import { db } from '../../app/container.js';
3	import { ValidationError, ConflictError } from '../errors/app-errors.js';
4	
5	const IDEMPOTENCY_TTL_MS = 24 * 60 * 60 * 1000; // 24 hours
6	const IN_FLIGHT_SENTINEL = ''; // empty string signals in-flight (no response yet)
7	
8	export function buildIdempotencyScope(req: Request): string {
9	  if (req.user) {
10	    return `user:${req.user.userId}:org:${req.user.orgId ?? 'platform'}`;
11	  }
12	  return `anonymous:${req.ip ?? 'unknown'}`;
13	}
14	
15	export function idempotency(req: Request, res: Response, next: NextFunction): void {
16	  const key = req.headers['x-idempotency-key'];
17	
18	  if (!key || typeof key !== 'string') {
19	    next();
20	    return;
21	  }
22	
23	  if (key.length > 64) {
24	    next(new ValidationError('X-Idempotency-Key must be 64 characters or fewer'));
25	    return;
26	  }
27	
28	  req.idempotencyKey = key;
29	  const scope = buildIdempotencyScope(req);
30	
31	  db.idempotencyRecord
32	    .findFirst({ where: { scope, key } })
33	    .then((record) => {
34	      const now = new Date();
35	
36	      if (record) {
37	        // Expired — delete and treat as new
38	        if (record.expiresAt < now) {
39	          return db.idempotencyRecord
40	            .delete({ where: { id: record.id } })
41	            .then(() => insertPendingAndContinue(scope, key, req, res, next));
42	        }
43	
44	        // In-flight: responseBody is empty string sentinel
45	        if (record.responseBody === IN_FLIGHT_SENTINEL) {
46	          next(new ConflictError('Request in progress'));
47	          return;
48	        }
49	
50	        // Replay: response body is populated — verify method/path match to prevent key reuse attacks
51	        if (record.method !== req.method || record.path !== req.path) {
52	          next(new ConflictError('Idempotency key already used for a different request'));
53	          return;
54	        }
55	        res.status(record.statusCode).json(JSON.parse(record.responseBody));
56	        return;
57	      }
58	
59	      return insertPendingAndContinue(scope, key, req, res, next);
60	    })
61	    .catch((err) => next(err));
62	}
63	
64	function insertPendingAndContinue(
65	  scope: string,
66	  key: string,
67	  req: Request,
68	  res: Response,
69	  next: NextFunction,
70	): Promise<void> {
71	  const expiresAt = new Date(Date.now() + IDEMPOTENCY_TTL_MS);
72	
73	  return db.idempotencyRecord
74	    .create({
75	      data: {
76	        scope,
77	        key,
78	        method: req.method,
79	        path: req.path,
80	        statusCode: 0,
81	        responseBody: IN_FLIGHT_SENTINEL,
82	        expiresAt,
83	      },
84	    })
85	    .then((created) => {
86	      const originalJson = res.json.bind(res);
87	
88	      res.json = function (body: unknown): Response {
89	        const statusCode = res.statusCode;
90	        const responseBody = JSON.stringify(body);
91	
92	        db.idempotencyRecord
93	          .update({
94	            where: { id: created.id },
95	            data: { statusCode, responseBody },
96	          })
97	          .catch(() => {
98	            // Best-effort persistence — do not fail the response
99	          });
100	
101	        return originalJson(body);
102	      };
103	
104	      next();
105	    });
106	}
