14	export function authenticate(req: Request, _res: Response, next: NextFunction): void {
15	  const authHeader = req.headers['authorization'];
16	  if (!authHeader || !authHeader.startsWith('Bearer ')) {
17	    next(new UnauthorizedError('Authentication required'));
18	    return;
19	  }
20	
21	  const token = authHeader.slice(7);
22	  try {
23	    const payload = jwt.verify(token, config.JWT_SECRET) as JwtPayload;
24	    const isAdministrator = payload.roles.includes('Administrator');
25	    if (!isAdministrator && !payload.orgId) {
26	      next(new UnauthorizedError('Organization context required'));
27	      return;
28	    }
29	    req.user = {
30	      userId: payload.userId,
31	      username: payload.username,
32	      roles: payload.roles,
33	      permissions: payload.permissions,
34	      orgId: payload.orgId,
35	    };
36	    next();
37	  } catch {
38	    next(new UnauthorizedError('Invalid or expired token'));
39	  }
40	}
41	
42	export function requirePermission(action: string, resource: string) {
43	  return (req: Request, _res: Response, next: NextFunction): void => {
44	    if (!req.user) {
45	      next(new UnauthorizedError('Authentication required'));
46	      return;
47	    }
48	
49	    const hasPermission = req.user.permissions.some((p) => {
50	      const [pAction, pResource, pScope] = p.split(':');
51	      const scopeMatch = !pScope || pScope === '*';
52	      return pAction === action && pResource === resource && scopeMatch;
53	    });
54	
55	    if (!hasPermission) {
56	      next(new ForbiddenError(`Permission denied: ${action}:${resource}`));
57	      return;
58	    }
59	    next();
60	  };
61	}
