64	 * Enforces org boundary on routes that include :orgId in their path.
65	 * When a JWT-authenticated user has an orgId, it must match the route's :orgId param.
66	 * Users without an orgId (e.g., platform administrators) bypass the check.
67	 * Apply after `authenticate` on all org-scoped routers.
68	 */
69	export function enforceSameOrg(req: Request, _res: Response, next: NextFunction): void {
70	  if (!req.user) {
71	    next(new UnauthorizedError('Authentication required'));
72	    return;
73	  }
74	
75	  const isAdministrator = req.user.roles.includes('Administrator');
76	  if (!isAdministrator && !req.user.orgId) {
77	    next(new ForbiddenError('Access denied: missing organization context'));
78	    return;
79	  }
80	
81	  if (!isAdministrator && req.params['orgId'] && req.user.orgId !== req.params['orgId']) {
82	    // Return not-found to avoid exposing tenant existence details.
83	    next(new NotFoundError('Resource not found'));
84	    return;
85	  }
86	  next();
87	}
