93	      return;
94	    }
95	
96	    const hasRole = req.user.roles.some((r) => roleNames.includes(r));
97	    if (!hasRole) {
98	      next(new ForbiddenError(`Role required: ${roleNames.join(' or ')}`));
99	      return;
100	    }
101	    next();
102	  };
103	}
