1	import winston from 'winston';
2	import TransportStream from 'winston-transport';
3	import { encrypt } from '../encryption/aes256.js';
4	
5	class DatabaseTransport extends TransportStream {
6	  log(info: Record<string, unknown>, callback: () => void): void {
7	    setImmediate(callback); // never block the logger
8	    // Lazy import to avoid circular dependency at module load time
9	    import('../../app/container.js').then(({ db }) => {
10	      const { level, message, ...rest } = info;
11	      const orgId = typeof rest['orgId'] === 'string' ? rest['orgId'] : null;
12	      const context = { ...rest };
13	      delete context['orgId'];
14	      const encryptedContext = encrypt(JSON.stringify(context));
15	      db.applicationLog.create({
16	        data: {
17	          level: String(level),
18	          message: typeof message === 'string' ? message : JSON.stringify(message),
19	          context: encryptedContext,
20	          orgId,
21	        },
22	      }).catch(() => {}); // swallow DB errors — never crash the logger
23	    }).catch(() => {});
24	  }
25	}
26	
27	const REDACTED_KEYS = new Set([
28	  'password',
29	  'passwordhash',
30	  'salt',
31	  'token',
32	  'secret',
33	  'key',
34	  'authorization',
35	  'encryptedbalance',
36	  'connectorconfig',
37	  'aeskey',
38	  'jwtsecret',
39	]);
40	
41	const BEARER_PATTERN = /Bearer\s+[A-Za-z0-9\-._~+/]+=*/g;
42	
43	function sanitizeValue(value: unknown): unknown {
44	  if (typeof value === 'string') {
45	    return value.replace(BEARER_PATTERN, 'Bearer [REDACTED]');
46	  }
47	  if (Array.isArray(value)) {
48	    return value.map(sanitizeValue);
49	  }
50	  if (value !== null && typeof value === 'object') {
51	    return sanitizeObject(value as Record<string, unknown>);
52	  }
53	  return value;
54	}
55	
56	function sanitizeObject(obj: Record<string, unknown>): Record<string, unknown> {
57	  const result: Record<string, unknown> = {};
58	  for (const [k, v] of Object.entries(obj)) {
59	    if (REDACTED_KEYS.has(k.toLowerCase())) {
60	      result[k] = '[REDACTED]';
61	    } else {
62	      result[k] = sanitizeValue(v);
63	    }
64	  }
65	  return result;
66	}
67	
68	const sanitizeTransform = winston.format((info) => {
69	  const sanitized = sanitizeObject(info as unknown as Record<string, unknown>);
70	  return Object.assign(info, sanitized);
71	});
72	
73	const isDev = process.env['NODE_ENV'] === 'development';
74	
75	export const logger = winston.createLogger({
76	  level: isDev ? 'debug' : 'info',
77	  format: isDev
78	    ? winston.format.combine(
79	        sanitizeTransform(),
80	        winston.format.colorize(),
81	        winston.format.simple(),
82	      )
83	    : winston.format.combine(sanitizeTransform(), winston.format.json()),
84	  transports: [
85	    new winston.transports.Console(),
86	    new DatabaseTransport({ level: 'info' }),
87	  ],
88	});
