1	import { db } from '../../app/container.js';
2	import { NotFoundError, ForbiddenError } from '../../common/errors/app-errors.js';
3	import { decrypt } from '../../common/encryption/aes256.js';
4	import type { LogSearchRequest } from './types.js';
5	
6	// ---- Metrics ----
7	
8	export async function insertMetric(data: { metricName: string; value: number; unit: string; orgId?: string }) {
9	  return db.runtimeMetric.create({ data });
10	}
11	
12	export async function getLatestMetrics(orgId?: string) {
13	  // Most recent value per distinct metric name, scoped to org when provided
14	  return db.runtimeMetric.findMany({
15	    where: orgId ? { orgId } : {},
16	    orderBy: { collectedAt: 'desc' },
17	    distinct: ['metricName'],
18	  });
19	}
20	
21	export async function getMetricHistory(metricName: string, since: Date, orgId?: string) {
22	  return db.runtimeMetric.findMany({
23	    where: { metricName, collectedAt: { gte: since }, ...(orgId ? { orgId } : {}) },
24	    orderBy: { collectedAt: 'asc' },
25	  });
26	}
27	
28	// ---- Logs ----
29	
30	export async function searchLogs(filters: LogSearchRequest, page = 1, limit = 50, orgId?: string) {
31	  const skip = (page - 1) * limit;
32	  const where: Record<string, unknown> = {};
33	
34	  if (filters.level) where.level = filters.level;
35	  if (filters.search) where.message = { contains: filters.search };
36	  if (orgId) where.orgId = orgId;
37	
38	  if (filters.startDate || filters.endDate) {
39	    const tsFilter: Record<string, Date> = {};
40	    if (filters.startDate) tsFilter.gte = new Date(filters.startDate);
41	    if (filters.endDate) tsFilter.lte = new Date(filters.endDate);
42	    where.timestamp = tsFilter;
43	  }
44	
45	  const [rawLogs, total] = await Promise.all([
46	    db.applicationLog.findMany({
47	      where,
48	      orderBy: { timestamp: 'desc' },
49	      skip,
50	      take: limit,
51	    }),
52	    db.applicationLog.count({ where }),
53	  ]);
54	
55	  const logs = rawLogs.map((log) => ({
56	    ...log,
57	    context: log.context
58	      ? (() => { try { return decrypt(log.context!); } catch { return log.context; } })()
59	      : null,
60	  }));
61	
62	  return { logs, total };
63	}
